// Space: O(1)

class Solution {
public:
    bool canConvert(string str1, string str2) {
        if (str1 == str2) {
            return true;
        }
        unordered_map<char, char> lookup;
        for (int i = 0; i < str1.size(); ++i) {
            lookup.emplace(str1[i], str2[i]);
            if (lookup[str1[i]] != str2[i]) {
                return false;
            }
        }
        unordered_set<char> count(str2.cbegin(), str2.cend());
        return count.size() < 26;
    }
};

# Time:  O(n)
# Space: O(1)

import itertools


class Solution(object):
    def canConvert(self, str1, str2):
        """
        :type str1: str
        :type str2: str
        :rtype: bool
        """
        if str1 == str2:
            return True
        lookup = {}
        for i, j in itertools.izip(str1, str2):
            if lookup.setdefault(i, j) != j:
                return False
        return len(set(str2)) < 26
